        id_usuario_solicitante,
        id_usuario_destinatario,
        id_jefe_aprobador,
        id_tesorero_aprobador,
        id_ciclo_caja,
        id_transaccion,
        id_usuario_creacion,
        id_usuario_modificacion
    )
    VALUES(
        p_fecha_solicitud,
        p_monto_solicitado,
        p_id_moneda_original,
        p_tipo_cambio,
        p_monto_convertido,
        p_motivo_solicitud,
        p_estado_solicitud,
