    IN p_id_usuario_accion INT,
IN p_nombre_area VARCHAR(60),
IN p_descripcion_area VARCHAR(500),
IN p_id_jefe INT,
OUT p_id_generado INT
)
BEGIN
    INSERT INTO rrhh_area(

        nombre_area,
        descripcion_area, 
        id_jefe, 
        esta_activo,
        id_usuario_creacion,
        id_usuario_modificacion    )
    VALUES(

